+        assert_eq!(chunks_ordered.len(), chunks_reversed.len());
+        for (a, b) in chunks_ordered.iter().zip(chunks_reversed.iter()) {
+            assert_eq!(a.chunk_id, b.chunk_id);
+            assert_eq!(a.text, b.text);
+            assert_eq!(a.content_hash, b.content_hash);
+        }
+    }
